// Hoisting ilə funksiya nümunəsi
console.log(sayHello()); // nəticə: Salam!
function sayHello() {
  return "Salam!";
}

// var ilə dəyişən hoisting
console.log(name); // nəticə: undefined
var name = "Aysel";

// var hoisting
console.log(counter); // nəticə: undefined
var counter = 10;
console.log(counter); // nəticə: 10

// let hoisting (xəta verir)
// console.log(age); // Xəta: Cannot access 'age' before initialization
let age = 20;

// Funksiya ifadəsi ilə hoisting
// console.log(greet()); // Xəta: Cannot access 'greet' before initialization
const greet = function() {
  return "Salam, qonaq!";
};

// Funksiya bəyanatı ilə hoisting
console.log(sayHi()); // nəticə: Salam, dünya!
function sayHi() {
  return "Salam, dünya!";
}

// Təhlükəli hoisting nümunəsi
console.log(item); // nəticə: undefined
item = "Çaydan";
console.log(item); // nəticə: Çaydan
var item;

