// Hoisting with a function
console.log(sayHello()); // Output: Hello!
function sayHello() {
  return "Hello!";
}

// var hoisting
console.log(name); // Output: undefined
var name = "Aysel";

// var hoisting
console.log(counter); // Output: undefined
var counter = 10;
console.log(counter); // Output: 10

// let hoisting (causes error)
// console.log(age); // Error: Cannot access 'age' before initialization
let age = 20;

// Function expression hoisting
// console.log(greet()); // Error: Cannot access 'greet' before initialization
const greet = function() {
  return "Hello, guest!";
};

// Function declaration hoisting
console.log(sayHi()); // Output: Hello, world!
function sayHi() {
  return "Hello, world!";
}

// Dangerous hoisting example
console.log(item); // Output: undefined
item = "Teapot";
console.log(item); // Output: Teapot
var item;

